static int _strbuf_reserve(strbuf *buf, size_t add) {
    size_t s = buf->size;
    if (s == 0) s = add + 1;
    while (s < add + 1) s *= 2;
    if (s != buf->size) {
        char *p = realloc(buf->buf, s);
        if (!p) return -1;
        buf->buf = p;
        buf->size = s;
    }
    return 0;
}

static int _strbuf_add_char(strbuf *buf, char c) {
    if (_strbuf_reserve(buf, 1) != 0) return -1;
    buf->buf[buf->len++] = c;
    buf->buf[buf->len] = '\0';
    return 0;
}

